/**
	 * Gets XPath for the current open tag.
	 *
	 * It would be nicer if this were like `.../DIV[1]/DIV[2]` but in XPath the position() here refers to the
	 * index of the preceding node set. So it has to rather be written `.../*[1][self::DIV]/*[2][self::DIV]`.
	 * Note that the first three levels lack any node index whereas the third level includes a disambiguating
	 * attribute predicate (e.g. `/HTML/BODY/DIV[@id="page"]`) for the reasons explained in {@see self::XPATH_PATTERN}.
	 * This predicate will be included once the transitional period is over.
	 *
	 * @since 0.4.0
	 *
	 * @return string XPath.
	 */
function get_xpath(): string {
		if ( null === $this->current_xpath ) {
			$this->current_xpath = '';
			foreach ( $this->get_indexed_breadcrumbs() as $i => list( $tag_name, $index, $attributes ) ) {
				if ( $i < 2 ) {
					$this->current_xpath .= "/$tag_name";
				} elseif ( 2 === $i && '/HTML/BODY' === $this->current_xpath ) {
					$segment = "/$tag_name";
					foreach ( $attributes as $attribute_name => $attribute_value ) {
						$segment .= sprintf(
							"[@%s='%s']",
							$attribute_name,
							$attribute_value // Note: $attribute_value has already been validated to only contain safe characters /^[a-zA-Z0-9_.\s:-]*/ which do not need escaping.
						);
					}
					$this->current_xpath .= $segment;
				} else {
					$this->current_xpath .= sprintf( '/*[%d][self::%s]', $index + 1, $tag_name );
				}
			}
		}
		return $this->current_xpath;
	}

/**
	 * Builds the Email Reporting pointer.
	 *
	 * @since 1.166.0
	 *
	 * @return Pointer
	 */
function get_email_reporting_pointer() {
		return new Pointer(
			self::SLUG,
			array(
				// Title allows limited markup (button/span) sanitized via wp_kses in Pointers::print_pointer_script.
				'title'           => sprintf(
					'%s %s',
					__( 'Get site insights in your inbox', 'google-site-kit' ),
					'<button type="button" class="googlesitekit-pointer-cta--dismiss dashicons dashicons-no" data-action="dismiss">' .
					'<span class="screen-reader-text">' . esc_html__( 'Dismiss this notice.', 'google-site-kit' ) . '</span>' .
					'</button>'
				),
				// Return subtitle and content as HTML with safe tags.
				'content'         => function () {
					return sprintf(
						'<h4>%s</h4><p>%s</p>',
						__( 'Keep track of your site with Site Kit', 'google-site-kit' ),
						__( 'Receive the most important insights about your site’s performance, key trends, and tailored metrics directly in your inbox', 'google-site-kit' )
					);
				},
				// Site Kit menu in WP Admin.
				'target_id'       => 'toplevel_page_googlesitekit-dashboard',
				'position'        => 'top',
				'active_callback' => function ( $hook_suffix ) {
					// Only on the main WP Dashboard screen.
					if ( 'index.php' !== $hook_suffix ) {
						return false;
					}

					// User must have Site Kit access: either admin (can authenticate) or view-only (can view splash).
					if ( ! current_user_can( Permissions::VIEW_DASHBOARD ) ) {
						return false;
					}

					// Check if user has access to at least one email report data module.
					// Admins can authenticate and have full access; view-only users need
					// READ_SHARED_MODULE_DATA capability for at least one module.
					$has_analytics_access      = current_user_can( Permissions::AUTHENTICATE )
						|| current_user_can( Permissions::READ_SHARED_MODULE_DATA, 'analytics-4' );
					$has_search_console_access = current_user_can( Permissions::AUTHENTICATE )
						|| current_user_can( Permissions::READ_SHARED_MODULE_DATA, 'search-console' );

					if ( ! $has_analytics_access && ! $has_search_console_access ) {
						return false;
					}

					// Do not show if this pointer was already dismissed via core 'dismiss-wp-pointer'.
					$user_id               = get_current_user_id();
					$dismissed_wp_pointers = get_user_meta( $user_id, 'dismissed_wp_pointers', true );
					if ( $dismissed_wp_pointers ) {
						$dismissed_wp_pointers = explode( ',', $dismissed_wp_pointers );
						if ( in_array( self::SLUG, $dismissed_wp_pointers, true ) ) {
							return false;
						}
					}

					// If user is already subscribed to email reporting, bail early.
					if ( $this->user_settings->is_user_subscribed() ) {
						return false;
					}

					// If the overlay notification has already been dismissed, bail early.
					if ( $this->dismissed_items->is_dismissed( 'email_reports_setup_overlay_notification' ) ) {
						return false;
					}

					return true;
				},
				'class'           => 'googlesitekit-email-pointer',
				'tracking'        => array(
					'view'    => array(
						'category' => 'wpDashboard_pointer_email_reports_setup_cta',
						'action'   => 'view_notification',
					),
					'dismiss' => array(
						'category' => 'wpDashboard_pointer_email_reports_setup_cta',
						'action'   => 'dismiss_notification',
					),
					'click'   => array(
						'category' => 'wpDashboard_pointer_email_reports_setup_cta',
						'action'   => 'confirm_notification',
					),
				),
				// Inline JS function to render CTA button and add delegated handlers for CTA and dismiss.
				'buttons'         => sprintf(
					'<a class="googlesitekit-pointer-cta button-primary" data-action="dismiss" href="%s">%s</a>',
					$this->context->admin_url( 'dashboard', array( 'panel' => 'email-reporting' ) ),
					esc_html__( 'Set up', 'google-site-kit' )
				),
			),
		);
	}

